const path = '~/contacts.yaml';
const text = await space.api.fileRead(path, 'utf8');
const data = space.utils.yaml.parse(text);
if (!data || typeof data !== 'object') throw new Error('contacts.yaml is not a YAML object');
let updated = false;

function expandValue(v) {
  if (typeof v === 'string' && v === 'mr_kowalski') {
    updated = true;
    return 'John Ronald Kowalski';
  }
  if (Array.isArray(v)) return v.map(expandValue);
  if (v && typeof v === 'object') {
    for (const k of Object.keys(v)) v[k] = expandValue(v[k]);
  }
  return v;
}

expandValue(data);

if (!updated) throw new Error('mr_kowalski not found in contacts.yaml');
const out = space.utils.yaml.stringify(data);
return await space.api.fileWrite(path, out, 'utf8');

